K-matrix.css:
*{margin:0;padding:0;box-sizing:border-box}
body{background:__BG_EXT__;display:flex;justify-content:center;padding:40px 0;font-family:-apple-system,'Microsoft YaHei','PingFang SC',sans-serif;-webkit-font-smoothing:antialiased}
.page{width:210mm;min-height:297mm;background:__BG__;box-shadow:0 0 0 0.5px rgba(0,0,0,0.05);position:relative;overflow:hidden}
@media print{body{background:#fff;padding:0}.page{box-shadow:none;margin:0;width:210mm;min-height:297mm}}

.hero-matrix{background:linear-gradient(160deg,__HERO_BG1__,__HERO_BG2__);padding:36px 20mm 28px;color:__HERO_TEXT__;clip-path:polygon(0 0,100% 0,100% 92%,0 100%)}
.hero-matrix h1{font-size:38pt;font-weight:800;letter-spacing:0.06em}
.hero-matrix .sub{font-size:10pt;color:__HERO_MUTED__;margin-top:6px;letter-spacing:0.04em}
.hero-matrix .contact{display:flex;gap:20px;margin-top:10px;font-size:8pt;color:__HERO_DIM__}
.matrix-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:12px;padding:20px 18mm}
.matrix-cell{background:__CARD__;border-radius:6px;padding:16px;border-left:4px solid __ACCENT__;box-shadow:0 0 0 0.5px rgba(0,0,0,0.06);border:0.5px solid __BORDER__}
.matrix-cell h3{font-size:11pt;color:__TEXT_DARK__;margin-bottom:6px}
.matrix-cell .items{display:flex;flex-wrap:wrap;gap:4px}
.matrix-chip{background:__TAG__;color:__ACCENT__;padding:3px 10px;border-radius:3px;font-size:7.5pt;border:0.5px solid __ACCENT__30}
.exp-strip{padding:16px 18mm;display:flex;flex-direction:column;gap:10px}
.exp-strip .row{display:flex;align-items:center;gap:12px;padding:8px 14px;background:__CARD2__;border-radius:4px;box-shadow:0 0 0 0.5px rgba(0,0,0,0.06);border:0.5px solid __BORDER__}
.exp-strip .row .date{font-size:8pt;color:__ACCENT__;min-width:70px;font-weight:600}
.exp-strip .row .info{flex:1}
.exp-strip .row .info b{font-size:11pt;color:__TEXT_DARK__}
.exp-strip .row .info span{font-size:8.5pt;color:__MUTED1__;margin-left:8px}
.foot-strip{padding:10px 18mm;border-top:1px solid __BORDER2__;font-size:7pt;color:__MUTED4__;display:flex;justify-content:space-between}

L-compare.css:
