.dash-panel h3{font-size:10pt;color:__ACCENT__;letter-spacing:0.08em;margin-bottom:12px;text-transform:uppercase}
.dash-panel .bar-row{display:flex;align-items:center;margin-bottom:8px;gap:8px}
.dash-panel .bar-row .label{font-size:8pt;color:__TEXT__;min-width:55px}
.dash-panel .bar-row .bar{flex:1;height:6px;background:__TAG__;border-radius:3px;overflow:hidden}
.dash-panel .bar-row .bar .fill{height:100%;background:__ACCENT__;border-radius:3px}
.dash-timeline{padding:0 18mm 20px}
.dash-timeline .tl-row{display:flex;align-items:center;padding:8px 14px;margin-bottom:6px;background:__CARD2__;border-radius:4px;gap:12px;box-shadow:0 0 0 0.5px rgba(0,0,0,0.06);border:0.5px solid __BORDER__}
.dash-timeline .tl-row .yr{font-size:10pt;font-weight:700;color:__ACCENT__;min-width:55px}
.dash-timeline .tl-row .desc{font-size:9pt;color:__TEXT__}

