.vis-hero::after{content:'';position:absolute;right:-30px;top:-30px;width:200px;height:200px;border:3px solid rgba(255,255,255,0.1);border-radius:50%}
.vis-hero h1{font-size:42pt;font-weight:800;letter-spacing:0.06em;position:relative;z-index:1}
.vis-hero .sub{font-size:11pt;opacity:0.9;margin-top:6px;position:relative;z-index:1}
.vis-body{display:grid;grid-template-columns:2fr 1fr;gap:16px;padding:20px 18mm}
.vis-main .sec{margin-bottom:18px}
.vis-main .sec h2{font-size:11pt;color:__ACCENT__;letter-spacing:0.08em;margin-bottom:10px;display:flex;align-items:center;gap:8px}
.vis-main .sec h2 .icon{width:24px;height:24px;background:__ACCENT__;border-radius:4px;display:flex;align-items:center;justify-content:center;color:#fff;font-size:12pt}
.vis-card{background:__CARD__;padding:14px 16px;border-radius:6px;margin-bottom:10px;box-shadow:0 0 0 0.5px rgba(0,0,0,0.06);border:0.5px solid __BORDER__;position:relative}
.vis-card .date{position:absolute;right:14px;top:14px;font-size:7pt;color:__ACCENT__;font-weight:600}
.vis-card b{font-size:11pt;color:__TEXT_DARK__}
.vis-card .role{font-size:9pt;color:__ACCENT__;margin:2px 0 6px}
.vis-card p{font-size:8.5pt;color:__MUTED1__;line-height:1.6}
.vis-side{padding-top:4px}
.vis-side .box{background:__TAG__;padding:16px;border-radius:6px;margin-bottom:12px;box-shadow:0 0 0 0.5px rgba(0,0,0,0.06);border:0.5px solid __BORDER__''}
.vis-side .box h3{font-size:9pt;color:__ACCENT__;margin-bottom:10px;letter-spacing:0.06em}

T-waterfall.css:
*{margin:0;padding:0;box-sizing:border-box}
body{background:__BG_EXT__;display:flex;justify-content:center;padding:40px 0;font-family:-apple-system,'Microsoft YaHei','PingFang SC',sans-serif;-webkit-font-smoothing:antialiased}
.page{width:210mm;min-height:297mm;background:__BG__;box-shadow:0 0 0 0.5px rgba(0,0,0,0.05);position:relative;overflow:hidden}
@media print{body{background:#fff;padding:0}.page{box-shadow:none;margin:0;width:210mm;min-height:297mm}}

.wf-header{padding:36px 20mm 20px;text-align:center;background:linear-gradient(180deg,__HERO_BG1__,transparent)}
.wf-header h1{font-size:40pt;font-weight:800;letter-spacing:0.08em;color:__HERO_TEXT__}
.wf-header .sub{font-size:10pt;color:__ACCENT__;margin-top:6px;letter-spacing:0.06em}
.wf-header .contact{font-size:8pt;color:__MUTED1__;margin-top:8px}
.wf-cascade{padding:0 20mm 20px;display:flex;flex-direction:column;align-items:center;gap:0}
.wf-item{width:85%;background:__CARD__;border-radius:8px;padding:18px 22px;margin-bottom:-6px;position:relative;box-shadow:0 0 0 0.5px rgba(0,0,0,0.06);border:0.5px solid __BORDER__''}
.wf-item:nth-child(odd){margin-right:60px;align-self:flex-start}
.wf-item:nth-child(even){margin-left:60px;align-self:flex-end}
