.wf-item .wf-date{font-size:8pt;color:__ACCENT__;font-weight:700;margin-bottom:6px}
.wf-item b{font-size:13pt;color:__TEXT_DARK__}
.wf-item .role{font-size:9pt;color:__ACCENT__;margin:4px 0 8px}
.wf-item p{font-size:8.5pt;color:__MUTED1__;line-height:1.6}
.wf-footer{text-align:center;padding:16px 20mm;background:__TAG__;border-top:1px solid __BORDER__;display:flex;flex-wrap:wrap;justify-content:center;gap:8px}
.wf-footer .chip{font-size:7.5pt;background:__CARD__;color:__ACCENT__;padding:4px 14px;border-radius:4px;border:0.5px solid __ACCENT__25}
